const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

module.exports = app;

class BadRequestError extends Error {
  constructor(message) {
    super(message);
    this.name = 'BadRequestError';
    this.statusCode = 400;
  }
}

class NotFoundError extends Error {
  constructor(message) {
    super(message);
    this.name = 'NotFoundError';
    this.statusCode = 404;
  }
}

module.exports = { BadRequestError, NotFoundError };

const crypto = require('crypto');

function generateId() {
  return crypto.randomUUID();
}

module.exports = { generateId };

const express = require('express');
const service = require('./service');
const { BadRequestError, NotFoundError } = require('../../lib/errors');

const router = express.Router({ mergeParams: true });

router.post('/', (req, res) => {
  const { message } = req.body;
  if (!message) throw new BadRequestError('Message is required');

  const comment = service.createComment(req.params.projectId, req.params.taskId, message);
  res.status(201).json({ comment });
});

router.get('/', (req, res) => {
  const comments = service.getComments(req.params.projectId, req.params.taskId);
  if (!comments) throw new NotFoundError('Task not found');

  res.json({ comments });
});

module.exports = router;

const { generateId } = require('../../lib/id');

const projects = {};

function createComment(projectId, taskId, message) {
  if (!projects[projectId] || !projects[projectId].tasks[taskId]) {
    throw new Error('Task not found');
  }

  const commentId = generateId();
  const comment = { id: commentId, message };

  projects[projectId].tasks[taskId].comments.push(comment);
  return comment;
}

function getComments(projectId, taskId) {
  if (!projects[projectId] || !projects[projectId].tasks[taskId]) {
    throw new Error('Task not found');
  }

  return projects[projectId].tasks[taskId].comments;
}

module.exports = { createComment, getComments };

const express = require('express');
const service = require('./service');
const { BadRequestError, NotFoundError } = require('../../lib/errors');

const router = express.Router({ mergeParams: true });

router.post('/', (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) throw new BadRequestError('UserId and role are required');

  const member = service.addMember(req.params.projectId, userId, role);
  res.status(201).json({ member });
});

router.get('/', (req, res) => {
  const members = service.getMembers(req.params.projectId);
  if (!members) throw new NotFoundError('Project not found');

  res.json({ members });
});

module.exports = router;

const { generateId } = require('../../lib/id');

const projects = {};

function addMember(projectId, userId, role) {
  if (!projects[projectId]) {
    throw new Error('Project not found');
  }

  const member = { id: generateId(), userId, role };

  projects[projectId].members.push(member);
  return member;
}

function getMembers(projectId) {
  if (!projects[projectId]) {
    throw new Error('Project not found');
  }

  return projects[projectId].members;
}

module.exports = { addMember, getMembers };

const express = require('express');
const service = require('./service');
const { BadRequestError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
