module.exports = router;

const { generateId } = require('../../lib/id');

const projects = {};

function createProject(name) {
  const projectId = generateId();
  const project = { id: projectId, name, members: [], tasks: [] };

  projects[projectId] = project;
  return project;
}

function getProjects() {
  return Object.values(projects);
}

module.exports = { createProject, getProjects };

const express = require('express');
const service = require('./service');
const { BadRequestError, NotFoundError } = require('../../lib/errors');

const router = express.Router({ mergeParams: true });

router.post('/', (req, res) => {
  const { title } = req.body;
  if (!title) throw new BadRequestError('Title is required');

  const task = service.createTask(req.params.projectId, title);
  res.status(201).json({ task });
});

router.get('/', (req, res) => {
  const tasks = service.getTasks(req.params.projectId, req.query.status);
  if (!tasks) throw new NotFoundError('Project not found');

  res.json({ tasks });
});

router.patch('/:taskId', (req, res) => {
  const { status } = req.body;
  if (!status) throw new BadRequestError('Status is required');

  const task = service.updateTask(req.params.projectId, req.params.taskId, status);
  if (!task) throw new NotFoundError('Task not found');

  res.json({ task });
});

module.exports = router;

const { generateId } = require('../../lib/id');

const projects = {};

function createTask(projectId, title) {
  if (!projects[projectId]) {
    throw new Error('Project not found');
  }

  const taskId = generateId();
  const task = { id: taskId, title, status: 'open', comments: [] };

  projects[projectId].tasks.push(task);
  return task;
}

function getTasks(projectId, status) {
  if (!projects[projectId]) {
    throw new Error('Project not found');
  }

  const tasks = projects[projectId].tasks;
  if (status) {
    return tasks.filter(task => task.status === status);
  }

  return tasks;
}

function updateTask(projectId, taskId, status) {
  if (!projects[projectId]) {
    throw new Error('Project not found');
  }

  const task = projects[projectId].tasks.find(task => task.id === taskId);
  if (task) {
    task.status = status;
  }

  return task;
}

module.exports = { createTask, getTasks, updateTask };

const app = require('./app');
const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});
